const GA_LOADED="undefined"!=typeof gtag;function trackEvent(t,e={}){if(GA_LOADED)try{gtag("event",t,e),console.log("📊 Analytics:",t,e)}catch(t){console.error("Analytics error:",t)}else console.log("[Analytics Debug]",t,e)}function trackPageView(t,e){if(GA_LOADED)try{gtag("event","page_view",{page_title:t,page_path:e}),console.log("📊 Page View:",t,e)}catch(t){console.error("Analytics error:",t)}else console.log("[Analytics Debug] Page View:",t,e)}function trackArtistView(t,e){trackEvent("artist_view",{artist_slug:t,artist_name:e,event_category:"Artist",event_label:e})}function trackArtworkClick(t,e=null,a=null){trackEvent("artwork_click",{artwork_title:t,artwork_id:e||t,artist_name:a,event_category:"Artwork",event_label:t})}function trackWhatsAppClick(t,e="unknown"){trackEvent("whatsapp_contact",{artist_name:t,contact_context:e,event_category:"Contact",event_label:t})}function trackShopFilter(t,e){trackEvent("shop_filter",{filter_type:t,filter_value:e,event_category:"Shop",event_label:`${t}: ${e}`})}function trackSearch(t,e="unknown"){trackEvent("search",{search_term:t,search_context:e,event_category:"Search",event_label:t})}window.trackEvent=trackEvent,window.trackPageView=trackPageView,window.trackArtistView=trackArtistView,window.trackArtworkClick=trackArtworkClick,window.trackWhatsAppClick=trackWhatsAppClick,window.trackShopFilter=trackShopFilter,window.trackSearch=trackSearch;